diff --git a/src/routing.mjs b/src/routing.mjs
index 5ef70f1..8fd7ab1 100644
--- a/src/routing.mjs
+++ b/src/routing.mjs
@@ -1,5 +1,9 @@
 export async function routeRequest(request, repository) {
-  const record = await repository.find(request.id);
+  const requestId = request.id?.trim();
+  if (!requestId) {
+    return { status: 400, body: { code: 'request_id_required' } };
+  }
+  const record = await repository.find(requestId);
   return record ? { status: 200, body: record } : { status: 404 };
 }

diff --git a/test/routing.test.mjs b/test/routing.test.mjs
index 4205070..935aae8 100644
--- a/test/routing.test.mjs
+++ b/test/routing.test.mjs
@@ -18,3 +18,10 @@ test('returns 404 when a valid ID is absent', async () => {
   assert.equal(result.status, 404);
 });
+
+test('rejects a missing ID before repository access', async () => {
+  const repository = { find: () => assert.fail('repository must not be called') };
+  const result = await routeRequest({}, repository);
+  assert.deepEqual(result, { status: 400, body: { code: 'request_id_required' } });
+});
